const importantKeywords = [
  "urgent",
  "asap",
  "action required",
  "deadline",
  "payment due",
  "invoice",
  "incident",
  "outage",
  "security",
  "failed",
  "production",
  "sev1",
  "sev2",
  "alert",
  "password",
  "verification",
  "suspend",
  "billing"
];

const vipSenders = [
  "@github.com",
  "@atlassian.net",
  "@google.com",
  "@microsoft.com",
  "@amazon.com"
];

function normalizeText(v) {
  return String(v || "").toLowerCase();
}

function getHeader(json, key) {
  const headers = json.headers || {};
  if (headers[key]) return String(headers[key]);
  const lowerKey = key.toLowerCase();
  const found = Object.keys(headers).find(k => String(k).toLowerCase() === lowerKey);
  return found ? String(headers[found]) : "";
}

const scored = items.map(({ json }) => {
  const subjectRaw = String(json.subject || "(no subject)");
  const fromRaw = String(json.from || getHeader(json, "from") || "");
  const dateRaw = String(json.date || getHeader(json, "date") || "");
  const textBody = String(json.textPlain || json.textHtml || "");

  const subject = normalizeText(subjectRaw);
  const from = normalizeText(fromRaw);
  const body = normalizeText(textBody);

  const matchedKeywords = importantKeywords.filter(k => subject.includes(k) || body.includes(k));
  const matchedVip = vipSenders.filter(d => from.includes(d));

  let score = matchedKeywords.length;
  if (subject.includes("re:")) score += 0.25;
  if (subject.includes("fwd:")) score += 0.25;
  if (matchedVip.length > 0) score += 1;

  const snippet = textBody.replace(/\s+/g, " ").trim().slice(0, 180);

  return {
    subject: subjectRaw,
    from: fromRaw,
    date: dateRaw,
    snippet,
    matchedKeywords,
    matchedVip,
    importanceScore: Number(score.toFixed(2)),
    isImportant: score >= 1
  };
});

const important = scored
  .filter(i => i.isImportant)
  .sort((a, b) => b.importanceScore - a.importanceScore)
  .slice(0, 20);

const summaryLines = important.map((m, idx) => {
  const reasons = [];
  if (m.matchedKeywords.length) reasons.push(`keywords: ${m.matchedKeywords.join(", ")}`);
  if (m.matchedVip.length) reasons.push(`vip: ${m.matchedVip.join(", ")}`);
  const reasonText = reasons.length ? ` [${reasons.join(" | ")}]` : "";
  return `${idx + 1}. ${m.subject} | from ${m.from || "unknown"} | score ${m.importanceScore}${reasonText}`;
});

const markdown = summaryLines.length
  ? [
      `Important email summary (${new Date().toISOString()})`,
      `Scanned: ${scored.length}`,
      `Flagged: ${important.length}`,
      "",
      ...summaryLines
    ].join("\n")
  : [
      `Important email summary (${new Date().toISOString()})`,
      `Scanned: ${scored.length}`,
      "",
      "No important emails found in this run."
    ].join("\n");

return [
  {
    json: {
      generatedAt: new Date().toISOString(),
      scannedCount: scored.length,
      importantCount: important.length,
      summary: markdown,
      importantMessages: important
    }
  }
];
